The issue is in the token refresh logic. Here's the fix:
```typescript
async function refreshToken(token: string): Promise<string> {
  const response = await fetch('/api/auth/refresh', {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}` }
  });
  if (!response.ok) throw new AuthError('Refresh failed');
  return response.json().then(r => r.access_token);
}
```
